import type { PublicCard } from '../../../types';

export const gcseRevisionCardsPart2: PublicCard[] = [
  // ── GEOMETRY & MEASURES — Part 2 (cards 151–180) ────────────────────────
  { id: 'dc-gcse-revision-0151', deck_id: 'deck-gcse-revision', front: 'What are the circle theorems?', back: '1. Angle in a semicircle = 90° (angle subtended by diameter).\n2. Angles subtended by the same arc (on the same side) are equal.\n3. Angle at centre = 2 × angle at circumference (same arc).\n4. Opposite angles of a cyclic quadrilateral add up to 180°.\n5. Tangent–radius: a tangent is perpendicular to the radius at the point of contact.\n6. Two tangents from an external point are equal in length.\n7. Alternate segment theorem: angle between tangent and chord = inscribed angle in alternate segment.\n\nGCSE Tip: Always state the theorem name as a reason in your working.', sort_order: 151 },
  { id: 'dc-gcse-revision-0152', deck_id: 'deck-gcse-revision', front: 'How do you prove two triangles are congruent?', back: 'Four conditions (any one is sufficient):\n  SSS — three sides equal\n  SAS — two sides and the included angle equal\n  ASA or AAS — two angles and a side equal\n  RHS — right angle, hypotenuse, and one other side equal\n\nNote: SSA (two sides and a NON-included angle) is NOT a valid congruence condition.\n\nGCSE Tip: State which condition applies and clearly match the corresponding vertices.', sort_order: 152 },
  { id: 'dc-gcse-revision-0153', deck_id: 'deck-gcse-revision', front: 'How do you identify and use properties of a rhombus?', back: 'Rhombus properties:\n  • All four sides equal\n  • Opposite angles equal; adjacent angles supplementary (sum 180°)\n  • Diagonals bisect each other at right angles (90°)\n  • Diagonals bisect the vertex angles\n  • 2 lines of symmetry; order-2 rotational symmetry\n\nGCSE Tip: A square is a special rhombus (all angles 90°). In calculations, use the diagonal bisecting property with Pythagoras.', sort_order: 153 },
  { id: 'dc-gcse-revision-0154', deck_id: 'deck-gcse-revision', front: 'What is the equation of a circle and how do you use it?', back: 'Circle with centre (a, b) and radius r: (x−a)² + (y−b)² = r²\nCircle centred at origin: x² + y² = r²\n\nTo find if a point is inside, on, or outside:\n  Calculate (x−a)² + (y−b)²\n  < r² → inside; = r² → on; > r² → outside.\n\nTangent at (x₁, y₁) for x²+y²=r²: x·x₁ + y·y₁ = r²\n\nGCSE Tip: A common question asks you to find the equation of the tangent to a circle at a given point.', sort_order: 154 },
  { id: 'dc-gcse-revision-0155', deck_id: 'deck-gcse-revision', front: 'How do you find the perimeter of a sector or arc?', back: 'Perimeter of a sector = arc length + 2 radii\n  = (θ/360) × 2πr + 2r\n\nExample: r = 10 cm, θ = 72°\n  Arc = (72/360) × 2π(10) = (1/5) × 20π = 4π cm\n  Perimeter = 4π + 20 ≈ 32.57 cm\n\nGCSE Tip: The perimeter includes both straight sides (each = radius). Students often forget to add the two radii.', sort_order: 155 },
  { id: 'dc-gcse-revision-0156', deck_id: 'deck-gcse-revision', front: 'How do you find the area of a segment of a circle?', back: 'Area of segment = Area of sector − Area of triangle\n\nArea of sector = (θ/360) × πr²\nArea of triangle = ½r² sin θ (using ½ab sin C with a=b=r and angle C=θ)\n\nExample: r = 8 cm, θ = 60°\n  Sector = (60/360)π(64) = 64π/6\n  Triangle = ½(64)sin60° = 32 × (√3/2) = 16√3\n  Segment = 64π/6 − 16√3 ≈ 33.51 − 27.71 ≈ 5.8 cm²\n\nGCSE Tip: Segment = sector MINUS triangle. Draw a clear diagram.', sort_order: 156 },
  { id: 'dc-gcse-revision-0157', deck_id: 'deck-gcse-revision', front: 'How do you calculate angles in a polygon?', back: 'Sum of interior angles = (n−2) × 180°\nEach interior angle of REGULAR polygon = (n−2)×180° / n\nEach exterior angle = 360° / n\n\nNumber of sides from exterior angle: n = 360 ÷ exterior angle\n\nExamples:\n  Pentagon (5): sum = 540°; each interior = 108°; exterior = 72°\n  Octagon (8): sum = 1080°; each interior = 135°; exterior = 45°\n\nGCSE Tip: Sum of ALL exterior angles of any polygon = 360°.', sort_order: 157 },
  { id: 'dc-gcse-revision-0158', deck_id: 'deck-gcse-revision', front: 'How do you calculate the volume of a frustum?', back: 'A frustum is a cone or pyramid with the top cut off.\n\nMethod:\n1. Find the volume of the full cone (V₁).\n2. Find the volume of the removed smaller cone (V₂).\n3. Volume of frustum = V₁ − V₂.\n\nUse similar triangles to find the height/radius of the removed cone.\n\nGCSE Tip: Always clearly identify the scale factor between the two similar cones. The heights (or radii) are in the same ratio.', sort_order: 158 },
  { id: 'dc-gcse-revision-0159', deck_id: 'deck-gcse-revision', front: 'How do you use the alternate segment theorem?', back: 'The angle between a tangent to a circle and a chord drawn from the point of tangency equals the inscribed angle subtending the same arc on the other side.\n\nPut simply: tangent-chord angle = inscribed angle in the alternate segment.\n\nGCSE Tip: Identify the tangent, chord, and which segment is the "alternate" one. This theorem often catches students who confuse it with the tangent-radius theorem.', sort_order: 159 },
  { id: 'dc-gcse-revision-0160', deck_id: 'deck-gcse-revision', front: 'How do you calculate with composite solids?', back: 'Split the solid into recognisable parts (cylinder + hemisphere, cone + cylinder, etc.), calculate volume/surface area of each, then add (or subtract if a section is removed).\n\nExample: Solid = cylinder (r=3, h=8) + hemisphere (r=3)\n  Vol = π(9)(8) + (2/3)π(27) = 72π + 18π = 90π cm³\n\nGCSE Tip: For surface area, only count exposed faces. The flat circle where two solids join is INTERNAL — do not count it twice.', sort_order: 160 },
  { id: 'dc-gcse-revision-0161', deck_id: 'deck-gcse-revision', front: 'What is the perpendicular from a centre to a chord?', back: 'The perpendicular from the centre of a circle to a chord bisects the chord.\n\nThis means: if OM ⊥ AB where O is centre and M is on AB, then AM = MB.\n\nGCSE Tip: This is a useful circle property in Pythagoras problems. If you know the chord length and perpendicular distance from centre, use Pythagoras to find the radius: r² = (chord/2)² + d²', sort_order: 161 },
  { id: 'dc-gcse-revision-0162', deck_id: 'deck-gcse-revision', front: 'How do you prove that a quadrilateral is a specific type?', back: 'Show using the relevant property:\n\n• Parallelogram: show opposite sides parallel (equal gradients) OR bisecting diagonals.\n• Rectangle: parallelogram + one right angle (perpendicular gradients).\n• Rhombus: parallelogram + all sides equal.\n• Square: all sides equal + right angle.\n• Trapezium: exactly one pair of parallel sides.\n\nGCSE Tip: In coordinate geometry, use gradient for parallel/perpendicular, and the distance formula for equal sides.', sort_order: 162 },
  { id: 'dc-gcse-revision-0163', deck_id: 'deck-gcse-revision', front: 'What is the formula for the midpoint and length of a line segment?', back: 'Midpoint of (x₁,y₁) and (x₂,y₂):\n  M = ((x₁+x₂)/2, (y₁+y₂)/2)\n\nLength (distance formula):\n  d = √[(x₂−x₁)² + (y₂−y₁)²]\n\nExample: A(1,3), B(7,11)\n  Midpoint = (4, 7)\n  Length = √(36+64) = √100 = 10\n\nGCSE Tip: The length formula is just Pythagoras applied to coordinates. Always label your substitution clearly.', sort_order: 163 },
  { id: 'dc-gcse-revision-0164', deck_id: 'deck-gcse-revision', front: 'How do you plan a construction using compass and ruler?', back: 'Common GCSE constructions:\n  1. 60° angle: equilateral triangle construction.\n  2. 90° angle: perpendicular bisector at a point.\n  3. Perpendicular from a point to a line.\n  4. Perpendicular bisector of a line.\n  5. Angle bisector.\n\nAll require only compass and straight edge (no protractor).\n\nGCSE Tip: Show all arcs. The examiner must see your construction method — never rub arcs out.', sort_order: 164 },
  { id: 'dc-gcse-revision-0165', deck_id: 'deck-gcse-revision', front: 'How do you recognise and work with isometric and orthographic drawings?', back: 'Isometric: 3D drawing on a triangular dot grid showing width, height, and depth on equal axes (120° between each).\nOrthographic: 2D views from front, side, and above (plan, front elevation, side elevation).\n\nGCSE Tip: On isometric paper, vertical lines stay vertical; lines going left/right follow the 30° grid lines. Plan view = view from directly above.', sort_order: 165 },
  { id: 'dc-gcse-revision-0166', deck_id: 'deck-gcse-revision', front: 'What is the angle bisector and perpendicular bisector used for in loci?', back: 'Perpendicular bisector of AB: locus of points equidistant from A and B.\nAngle bisector of angle ABC: locus of points equidistant from lines AB and BC.\n\nRegion problems: "closer to A than B" = region on the same side of the perpendicular bisector as A.\n"closer to AB than BC" = region on the AB side of the angle bisector.\n\nGCSE Tip: Shaded region questions combine multiple loci. Construct each, then identify the intersection.', sort_order: 166 },
  { id: 'dc-gcse-revision-0167', deck_id: 'deck-gcse-revision', front: 'How do you find the surface area of a triangular prism?', back: 'SA = 2 × (area of triangular face) + 3 × (area of rectangular face)\n\nNote: the three rectangular faces may be different sizes.\n\nExample: Right-angled triangle sides 3, 4, 5 cm; length 10 cm.\n  Triangular faces: 2 × ½(3)(4) = 12 cm²\n  Rectangles: (3×10) + (4×10) + (5×10) = 30+40+50 = 120 cm²\n  SA = 132 cm²\n\nGCSE Tip: Always identify the cross-section (triangle) and list all five faces separately.', sort_order: 167 },
  { id: 'dc-gcse-revision-0168', deck_id: 'deck-gcse-revision', front: 'How do you work with plans and elevations?', back: 'Plan: view from directly above (bird\'s eye view).\nFront elevation: view from the front.\nSide elevation: view from the side.\n\nGCSE Tip: Hidden edges are shown as dashed lines. Visualise each view separately — imagine looking straight at the object from each direction. Practise with simple L-shaped solids.', sort_order: 168 },
  { id: 'dc-gcse-revision-0169', deck_id: 'deck-gcse-revision', front: 'What is a cross-section and how is it related to volume?', back: 'A cross-section is the shape you get when you cut through a 3D solid perpendicular to its length/height.\n\nVolume of prism = area of cross-section × length.\n\nIf the cross-section changes (e.g. a pyramid, cone), use the appropriate formula instead.\n\nGCSE Tip: Identify the cross-section first. For a swimming pool shape — often a trapezium cross-section — calculate the trapezoidal area, then multiply by the width.', sort_order: 169 },
  { id: 'dc-gcse-revision-0170', deck_id: 'deck-gcse-revision', front: 'How do you calculate with negative scale factors in enlargement?', back: 'A negative scale factor k means:\n  • The image is on the OPPOSITE side of the centre of enlargement.\n  • The image is rotated 180° (inverted) relative to the object.\n  • Distances are scaled by |k| as normal.\n\nExample: Scale factor −2, centre (0,0).\n  Point (1,2) → image at (−2, −4) (multiply by −2).\n\nGCSE Tip: The image is inverted and placed the other side of the centre. Describe as "enlargement, scale factor −2, centre (0,0)".', sort_order: 170 },
  { id: 'dc-gcse-revision-0171', deck_id: 'deck-gcse-revision', front: 'What is the formula for the area of a parallelogram?', back: 'Area = base × perpendicular height\n(NOT the slant height)\n\nExample: base = 7 cm, perpendicular height = 4 cm\n  Area = 28 cm²\n\nAlternatively: Area = ab sin C (where a, b are adjacent sides, C is the included angle).\n\nGCSE Tip: A parallelogram can be rearranged into a rectangle with the same base and height — hence the formula is the same as for a rectangle.', sort_order: 171 },
  { id: 'dc-gcse-revision-0172', deck_id: 'deck-gcse-revision', front: 'How do you identify line symmetry and rotational symmetry?', back: 'Line symmetry: the number of mirror lines where the shape folds onto itself.\n  Square = 4; Rectangle = 2; Equilateral triangle = 3; Circle = infinite.\n\nRotational symmetry: number of times shape maps onto itself in a full 360° rotation (order).\n  Square = order 4; Rectangle = order 2; Equilateral triangle = order 3.\n\nGCSE Tip: Every shape has at least order-1 rotational symmetry (original position). Only order > 1 counts as having rotational symmetry.', sort_order: 172 },
  { id: 'dc-gcse-revision-0173', deck_id: 'deck-gcse-revision', front: 'How do you calculate angles using isosceles triangles?', back: 'Isosceles triangle: two equal sides → two equal BASE angles.\n\nIf the apex angle = 40°:\n  base angles = (180° − 40°)/2 = 70° each.\n\nCommon in circle theorem questions (e.g. two radii form an isosceles triangle).\n\nGCSE Tip: Whenever you see two radii in a triangle, the triangle is isosceles (both sides = r). Use this to find angles.', sort_order: 173 },
  { id: 'dc-gcse-revision-0174', deck_id: 'deck-gcse-revision', front: 'What are the nets of 3D shapes?', back: 'Net: a flat 2D shape that can be folded to make a 3D solid.\n\n• Cube: 6 squares in a cross or T-shape.\n• Cuboid: 3 pairs of rectangles.\n• Triangular prism: 2 triangles + 3 rectangles.\n• Cylinder: 2 circles + 1 rectangle (width = circumference).\n• Cone: 1 circle + 1 sector.\n• Pyramid: square base + 4 triangles.\n\nGCSE Tip: Practice drawing nets and identifying which faces connect. The circumference of the circle must equal the width of the rectangle for a cylinder net.', sort_order: 174 },
  { id: 'dc-gcse-revision-0175', deck_id: 'deck-gcse-revision', front: 'How do you find the diagonal of a rectangle?', back: 'Use Pythagoras\' theorem.\n\nd² = l² + w²\nd = √(l² + w²)\n\nExample: 6 cm × 8 cm rectangle\n  d = √(36 + 64) = √100 = 10 cm\n\nGCSE Tip: The two diagonals of a rectangle are equal in length and bisect each other. The half-diagonal = √(l² + w²)/2.', sort_order: 175 },
  { id: 'dc-gcse-revision-0176', deck_id: 'deck-gcse-revision', front: 'How do angles relate in a cyclic quadrilateral?', back: 'Cyclic quadrilateral: all four vertices lie on a circle.\n\nOpposite angles add up to 180° (supplementary).\n  ∠A + ∠C = 180° and ∠B + ∠D = 180°\n\nAlso: an exterior angle of a cyclic quadrilateral equals the opposite interior angle.\n\nGCSE Tip: State: "opposite angles in a cyclic quadrilateral are supplementary" as your reason. This is a key circle theorem.', sort_order: 176 },
  { id: 'dc-gcse-revision-0177', deck_id: 'deck-gcse-revision', front: 'What is the tangent to a circle at a point?', back: 'A tangent to a circle:\n  • Touches the circle at exactly one point.\n  • Is perpendicular to the radius at that point (tangent-radius = 90°).\n  • Two tangents from the same external point are equal in length.\n\nGCSE Tip: If a right angle is formed at the tangent-circle intersection, you can use Pythagoras or trigonometry to find missing lengths.', sort_order: 177 },
  { id: 'dc-gcse-revision-0178', deck_id: 'deck-gcse-revision', front: 'How do you find the centre and radius from the circle equation?', back: 'Standard form: (x−a)² + (y−b)² = r²\n  Centre = (a, b); Radius = r\n\nExpanded form: x² + y² + cx + dy + e = 0\n  Complete the square for x and y to find centre and radius.\n\nExample: x² + y² − 6x + 4y − 12 = 0\n  (x−3)² − 9 + (y+2)² − 4 − 12 = 0\n  (x−3)² + (y+2)² = 25\n  Centre = (3, −2); r = 5\n\nGCSE Tip: Complete the square on both x and y terms.', sort_order: 178 },
  { id: 'dc-gcse-revision-0179', deck_id: 'deck-gcse-revision', front: 'What are angle properties of regular polygons?', back: 'Regular polygon: all sides and angles equal.\n\n  Equilateral triangle: 60° interior\n  Square: 90° interior\n  Regular pentagon: 108° interior\n  Regular hexagon: 120° interior\n  Regular octagon: 135° interior\n  Regular decagon: 144° interior\n\nGCSE Tip: A regular hexagon can be divided into 6 equilateral triangles. This helps in area and tiling problems.', sort_order: 179 },
  { id: 'dc-gcse-revision-0180', deck_id: 'deck-gcse-revision', front: 'How do you use the cosine rule to find a side?', back: 'a² = b² + c² − 2bc cos A\n\nwhere A is the angle OPPOSITE side a, and b, c are the other two sides.\n\nExample: b=7, c=9, A=60°\n  a² = 49 + 81 − 2(7)(9)cos60° = 130 − 63 = 67\n  a = √67 ≈ 8.19\n\nGCSE Tip: Use the cosine rule when you have SAS (two sides + included angle) or SSS (all three sides). For ASA or AAS, use the sine rule.', sort_order: 180 },

  // ── TRIGONOMETRY (cards 181–210) ─────────────────────────────────────────
  { id: 'dc-gcse-revision-0181', deck_id: 'deck-gcse-revision', front: 'What is SOH CAH TOA?', back: 'For a right-angled triangle with angle θ:\n\n  sin θ = Opposite / Hypotenuse\n  cos θ = Adjacent / Hypotenuse\n  tan θ = Opposite / Adjacent\n\nMemory aid: SOH CAH TOA\n\nGCSE Tip: Label the triangle first: identify the hypotenuse (longest side), opposite (faces θ), adjacent (next to θ). Then choose the correct ratio.', sort_order: 181 },
  { id: 'dc-gcse-revision-0182', deck_id: 'deck-gcse-revision', front: 'How do you find a missing side using trigonometry?', back: 'Choose the appropriate trig ratio, rearrange, calculate.\n\nExample: Find the opposite side if angle = 35°, adjacent = 10 cm.\n  tan 35° = opp/10 → opp = 10 × tan 35° ≈ 7.00 cm\n\nFor the hypotenuse: cos θ = adj/hyp → hyp = adj/cos θ\n\nGCSE Tip: Cover the unknown in the formula triangle to see whether to multiply or divide.', sort_order: 182 },
  { id: 'dc-gcse-revision-0183', deck_id: 'deck-gcse-revision', front: 'How do you find a missing angle using trigonometry?', back: 'Use the inverse trig function (sin⁻¹, cos⁻¹, tan⁻¹).\n\nExample: opp = 5 cm, hyp = 10 cm → sin θ = 5/10 = 0.5\n  θ = sin⁻¹(0.5) = 30°\n\nExample: adj = 6, opp = 8 → tan θ = 8/6 = 4/3\n  θ = tan⁻¹(4/3) ≈ 53.1°\n\nGCSE Tip: Press shift/2nd + sin/cos/tan on your calculator. Angles are in DEGREES unless stated otherwise.', sort_order: 183 },
  { id: 'dc-gcse-revision-0184', deck_id: 'deck-gcse-revision', front: 'What are the exact trigonometric values to memorise?', back: 'θ     sin θ   cos θ   tan θ\n0°    0       1       0\n30°   ½       √3/2    1/√3 = √3/3\n45°   √2/2    √2/2    1\n60°   √3/2    ½       √3\n90°   1       0       undefined\n\nGCSE Tip: Draw a right-angled equilateral triangle (sides 1,1,√2) for 45°, and half an equilateral triangle (sides 1,2,√3) for 30° and 60°. No calculator needed for these.', sort_order: 184 },
  { id: 'dc-gcse-revision-0185', deck_id: 'deck-gcse-revision', front: 'How do you apply trigonometry in 3D problems?', back: 'Identify the right-angled triangle within the 3D diagram:\n  1. Draw (or describe) the triangle.\n  2. Label known and unknown sides/angles.\n  3. Apply SOH CAH TOA or Pythagoras.\n\nExample: Finding the angle between a diagonal and the base of a cuboid:\n  Base diagonal d₁ = √(l²+w²)\n  Angle with base = tan⁻¹(h / d₁)\n\nGCSE Tip: Always state which triangle you are using and label it clearly.', sort_order: 185 },
  { id: 'dc-gcse-revision-0186', deck_id: 'deck-gcse-revision', front: 'What is the sine rule and when do you use it?', back: 'a/sin A = b/sin B = c/sin C\n(or equivalently: sin A/a = sin B/b = sin C/c)\n\nUse when: given AAS, ASA, or SSA (ambiguous case).\n\nFinding a side: a = b sin A / sin B\nFinding an angle: sin A = a sin B / b\n\nExample: a=7, b=9, B=60° → sin A = 7 sin 60°/9 ≈ 0.6736 → A ≈ 42.4°\n\nGCSE Tip: Use the sine rule when you DON\'T have a right angle and you know an angle and its opposite side.', sort_order: 186 },
  { id: 'dc-gcse-revision-0187', deck_id: 'deck-gcse-revision', front: 'What is the cosine rule and when do you use it?', back: 'Finding a side: a² = b² + c² − 2bc cos A\nFinding an angle: cos A = (b² + c² − a²) / (2bc)\n\nUse when: given SAS (two sides + included angle) or SSS (all three sides).\n\nGCSE Tip: Choose between sine and cosine rules:\n  • Have angle + opposite side → sine rule\n  • Have SAS or SSS → cosine rule\n  • Always check for right angles first — use SOH CAH TOA if present.', sort_order: 187 },
  { id: 'dc-gcse-revision-0188', deck_id: 'deck-gcse-revision', front: 'How do you find the area of a non-right triangle?', back: 'Area = ½ × a × b × sin C\n\nwhere a and b are two sides and C is the INCLUDED angle between them.\n\nExample: a=5, b=8, C=40°\n  Area = ½(5)(8)sin40° = 20 × 0.6428 ≈ 12.86 cm²\n\nGCSE Tip: The included angle is the one BETWEEN the two given sides. This formula works for any triangle, including obtuse-angled ones.', sort_order: 188 },
  { id: 'dc-gcse-revision-0189', deck_id: 'deck-gcse-revision', front: 'What is the ambiguous case of the sine rule?', back: 'When given SSA (two sides and a non-included angle), there may be 0, 1, or 2 possible triangles.\n\nIf sin A = a sin B/b > 1 → no solution.\nIf sin A < 1 → one solution is A₁ = sin⁻¹(value); the other is A₂ = 180° − A₁.\n  Check if A₂ is valid (A₂ + B < 180°).\n\nGCSE Tip: The exam may ask "show there are two possible triangles" — find both angle values and verify both give a valid triangle.', sort_order: 189 },
  { id: 'dc-gcse-revision-0190', deck_id: 'deck-gcse-revision', front: 'How do you solve trigonometric equations in a given range?', back: 'Example: Solve sin x = 0.5 for 0° ≤ x ≤ 360°\n  Principal value: x = sin⁻¹(0.5) = 30°\n  Sin is positive in Q1 and Q2: x = 30° and 180°−30° = 150°\n\nFor cos: positive in Q1 and Q4 → x and 360°−x\nFor tan: positive in Q1 and Q3 → x and 180°+x\n\nGCSE Tip: Draw a CAST diagram (All, Sin, Tan, Cos positive in Q1–Q4) to find all solutions in the range.', sort_order: 190 },
  { id: 'dc-gcse-revision-0191', deck_id: 'deck-gcse-revision', front: 'What is the CAST diagram?', back: 'CAST diagram shows which trig ratios are POSITIVE in each quadrant:\n  Q1 (0°–90°):    All positive\n  Q2 (90°–180°):  Sin positive\n  Q3 (180°–270°): Tan positive\n  Q4 (270°–360°): Cos positive\n\nAll – Sin – Tan – Cos (reading anticlockwise from Q4, or "All Students Take Calculus")\n\nGCSE Tip: Use the CAST diagram to find all angles in [0°, 360°] from the principal value given by your calculator.', sort_order: 191 },
  { id: 'dc-gcse-revision-0192', deck_id: 'deck-gcse-revision', front: 'How do you find angles of elevation and depression?', back: 'Angle of elevation: angle measured upward from the horizontal to a line of sight.\nAngle of depression: angle measured downward from the horizontal to a line of sight.\n\nThey are equal in magnitude when the two observers are at the same height on alternate sides (alternate angles).\n\nGCSE Tip: Draw a right-angled triangle. The horizontal is the adjacent, the vertical height difference is the opposite. Apply tan θ = opp/adj.', sort_order: 192 },
  { id: 'dc-gcse-revision-0193', deck_id: 'deck-gcse-revision', front: 'How do you apply the sine rule to bearing problems?', back: 'In navigation problems involving bearings:\n  1. Draw a clear diagram with North arrows at each point.\n  2. Calculate the angles of the triangle from the bearings.\n  3. Apply the sine or cosine rule.\n\nNote: Alternate angles with parallel North lines help identify triangle angles.\n\nGCSE Tip: The angle of the triangle is often NOT the bearing itself — subtract from 180° or 360° as needed. Always draw the diagram carefully.', sort_order: 193 },
  { id: 'dc-gcse-revision-0194', deck_id: 'deck-gcse-revision', front: 'How does sin, cos, and tan relate to the unit circle?', back: 'On a unit circle (radius 1) with angle θ from the positive x-axis:\n  cos θ = x-coordinate of the point\n  sin θ = y-coordinate of the point\n  tan θ = sin θ / cos θ = y/x\n\nThis explains why:\n  sin 90° = 1 (top of circle, y=1)\n  cos 0° = 1 (rightmost point, x=1)\n  tan 90° is undefined (division by 0)\n\nGCSE Tip: Understanding the unit circle explains the shape of the sin and cos graphs.', sort_order: 194 },
  { id: 'dc-gcse-revision-0195', deck_id: 'deck-gcse-revision', front: 'What is the identity sin²θ + cos²θ = 1?', back: 'This is the Pythagorean identity: true for all values of θ.\n\nDerived from the unit circle: x² + y² = 1, where x = cos θ and y = sin θ.\n\nUseful rearrangements:\n  sin²θ = 1 − cos²θ\n  cos²θ = 1 − sin²θ\n\nGCSE Tip: Used in Higher-tier algebraic proofs and simplification. Also: tan θ = sin θ / cos θ is a related identity.', sort_order: 195 },
  { id: 'dc-gcse-revision-0196', deck_id: 'deck-gcse-revision', front: 'How do you find the height of a triangle using trigonometry?', back: 'Draw an altitude from the apex to the base, creating two right-angled triangles.\n\nExample: Isosceles triangle, apex angle 40°, equal sides 12 cm.\n  Half of apex angle = 20° (altitude bisects apex angle).\n  Height h = 12 cos 20° ≈ 11.28 cm\n  (or use: h = 12 sin 70° ≈ 11.28 cm)\n\nGCSE Tip: Splitting non-right triangles into right-angled ones by dropping a perpendicular is a common technique.', sort_order: 196 },
  { id: 'dc-gcse-revision-0197', deck_id: 'deck-gcse-revision', front: 'How do you calculate trigonometry in problems involving multiple triangles?', back: 'Work systematically: solve one triangle first (find missing sides/angles), carry results forward into the next.\n\nExample: In a 3D problem, find the base diagonal using Pythagoras, then use it as a side in the second triangle to find the required angle with trig.\n\nGCSE Tip: Use the exact (unrounded) value from the first calculation as input to the second. Only round at the final step.', sort_order: 197 },
  { id: 'dc-gcse-revision-0198', deck_id: 'deck-gcse-revision', front: 'What is the graph of y = sin(x) and how do transformations affect it?', back: 'y = sin(x): period 360°, amplitude 1.\n\ny = a sin(x): amplitude = |a| (vertical stretch)\ny = sin(bx): period = 360°/b (horizontal stretch by 1/b)\ny = sin(x) + c: shift up by c\ny = sin(x + d): shift LEFT by d\n\nExample: y = 3 sin(2x) has amplitude 3 and period 180°.\n\nGCSE Tip: The b value changes the period — a common exam question.', sort_order: 198 },
  { id: 'dc-gcse-revision-0199', deck_id: 'deck-gcse-revision', front: 'How do you use trigonometry to find the side of a right-angled triangle in exact form?', back: 'Use exact trig values (30°, 45°, 60°) and leave the answer as a surd.\n\nExample: hyp = 8 cm, θ = 60°.\n  opp = 8 sin 60° = 8 × (√3/2) = 4√3 cm\n  adj = 8 cos 60° = 8 × (1/2) = 4 cm\n\nGCSE Tip: "Give exact answer" means leave it as a surd or fraction — do not press = to get a decimal.', sort_order: 199 },
  { id: 'dc-gcse-revision-0200', deck_id: 'deck-gcse-revision', front: 'How do you solve a triangle given three sides (SSS) using the cosine rule?', back: 'Rearranged cosine rule for an angle:\n  cos A = (b² + c² − a²) / (2bc)\n\nExample: a=5, b=7, c=8. Find angle A.\n  cos A = (49 + 64 − 25) / (2×7×8) = 88/112 = 11/14\n  A = cos⁻¹(11/14) ≈ 38.2°\n\nFind remaining angles with sine rule (or cosine rule again), then check sum = 180°.\n\nGCSE Tip: Find the largest angle first (opposite the longest side) to avoid the ambiguous case.', sort_order: 200 },
  { id: 'dc-gcse-revision-0201', deck_id: 'deck-gcse-revision', front: 'How do you use bearings with the cosine rule?', back: 'Steps:\n1. Draw accurate diagram with North lines at each point.\n2. Identify the angle of the triangle at each vertex (from the bearings).\n3. Apply the cosine or sine rule as appropriate.\n\nExample: A to B: bearing 040°, distance 50 km; A to C: bearing 130°, distance 70 km.\n  Angle BAC = 130° − 40° = 90°. Use Pythagoras: BC = √(50²+70²) = √7400 ≈ 86 km.\n\nGCSE Tip: Draw the North arrow at each point; the angle between two directions is found by subtracting bearings.', sort_order: 201 },
  { id: 'dc-gcse-revision-0202', deck_id: 'deck-gcse-revision', front: 'What is the difference between a right triangle and an oblique triangle in trig?', back: 'Right triangle: one angle = 90°. Use SOH CAH TOA and Pythagoras.\nOblique triangle: no right angle. Use the sine rule, cosine rule, or ½ab sin C.\n\nDecision guide:\n  • Right angle → SOH CAH TOA\n  • Angle + opposite side given → sine rule\n  • SAS or SSS → cosine rule\n  • Need area, have two sides + included angle → ½ab sin C\n\nGCSE Tip: These rules appear in the same question — work through methodically.', sort_order: 202 },
  { id: 'dc-gcse-revision-0203', deck_id: 'deck-gcse-revision', front: 'How do you use trigonometry to find angles in isosceles triangles?', back: 'Method 1: Drop a perpendicular from the apex to bisect the base → two congruent right-angled triangles → apply SOH CAH TOA.\n\nMethod 2: Use the cosine rule with the two equal sides and the base.\n\nExample: Equal sides = 10, base = 12. Find apex angle.\n  Draw perpendicular: right triangle with opp = 6, hyp = 10.\n  sin(apex/2) = 6/10 = 0.6 → apex/2 = 36.87° → apex ≈ 73.7°\n\nGCSE Tip: Method 1 (split in half) is usually simpler for isosceles triangles.', sort_order: 203 },
  { id: 'dc-gcse-revision-0204', deck_id: 'deck-gcse-revision', front: 'How do you use trig to solve problems on inclined planes?', back: 'An inclined plane (ramp) makes an angle with the horizontal.\nVertical height h = d × sin θ (d = distance along slope, θ = angle of inclination).\nHorizontal distance = d × cos θ.\n\nExample: Slope length 20 m, angle 30°.\n  Vertical rise = 20 sin 30° = 10 m.\n  Horizontal = 20 cos 30° = 10√3 ≈ 17.3 m.\n\nGCSE Tip: Identify the right-angled triangle formed by the slope, vertical, and horizontal.', sort_order: 204 },
  { id: 'dc-gcse-revision-0205', deck_id: 'deck-gcse-revision', front: 'What is the period and amplitude of a trigonometric function?', back: 'Amplitude: the maximum displacement from the centre line (half the peak-to-peak distance).\n  y = a sin x → amplitude = |a|\n\nPeriod: the x-distance for one complete cycle.\n  y = sin(bx) → period = 360°/b\n\nExamples:\n  y = 4 cos(3x): amplitude = 4, period = 120°\n  y = ½ sin(x/2): amplitude = ½, period = 720°\n\nGCSE Tip: Amplitude affects vertical scale; period affects horizontal scale.', sort_order: 205 },
  { id: 'dc-gcse-revision-0206', deck_id: 'deck-gcse-revision', front: 'How do you use tan to find a gradient?', back: 'The gradient of a line = tan θ, where θ is the angle the line makes with the positive x-axis.\n\nConversely: θ = tan⁻¹(gradient)\n\nExample: Line y = 2x + 1 has gradient 2.\n  θ = tan⁻¹(2) ≈ 63.4° to the horizontal.\n\nGCSE Tip: A line with gradient m rises at an angle θ = tan⁻¹(m) above horizontal. Negative gradient → line slopes downward.', sort_order: 206 },
  { id: 'dc-gcse-revision-0207', deck_id: 'deck-gcse-revision', front: 'How do you solve equations like 2 sin x = 1 in a given range?', back: '2 sin x = 1 → sin x = 0.5\nPrincipal value: x = sin⁻¹(0.5) = 30°\nFor 0° ≤ x ≤ 360°: sin positive in Q1 and Q2.\n  x = 30° and x = 180° − 30° = 150°\n\nFor 2 cos x + 1 = 0 → cos x = −0.5 → x = 120° and 240°.\n\nGCSE Tip: Always isolate sin/cos/tan first. Then use the CAST diagram to find all solutions in the range.', sort_order: 207 },
  { id: 'dc-gcse-revision-0208', deck_id: 'deck-gcse-revision', front: 'What is meant by a right angle in a semicircle (Thales\' theorem)?', back: 'Thales\' theorem (circle theorem 1): the angle in a semicircle is 90°.\n\nIf AB is a diameter and P is any other point on the circle, then ∠APB = 90°.\n\nThis is because: angle at centre = 2 × angle at circumference (the angle at the centre for a diameter is 180°).\n\nGCSE Tip: Whenever you see a diameter and a point on the circle, a 90° angle is formed. Mark it immediately and use Pythagoras or trig.', sort_order: 208 },
  { id: 'dc-gcse-revision-0209', deck_id: 'deck-gcse-revision', front: 'How do you use trigonometry to find the area of a regular polygon?', back: 'Divide the regular polygon into n congruent isosceles triangles from the centre.\n  Area of one triangle = ½r² sin(360°/n)\n  Total area = n × ½r² sin(360°/n)\n\nAlternatively (using apothem a = perpendicular distance from centre to side):\n  Area = ½ × perimeter × apothem\n\nGCSE Tip: For a regular hexagon with side s: Area = (3√3/2)s². Six equilateral triangles, each with area (√3/4)s².', sort_order: 209 },
  { id: 'dc-gcse-revision-0210', deck_id: 'deck-gcse-revision', front: 'What is the formula for trig in a right-angled isosceles triangle?', back: 'Right-angled isosceles triangle: two legs equal (length a), hypotenuse = a√2, angles 45°-45°-90°.\n\n  sin 45° = cos 45° = 1/√2 = √2/2\n  tan 45° = 1\n\nExample: leg = 5 cm → hypotenuse = 5√2 cm.\n\nGCSE Tip: This triangle comes from a square cut diagonally. Know that √2/2 ≈ 0.707 for non-calculator estimation.', sort_order: 210 },

  // ── STATISTICS (cards 211–250) ────────────────────────────────────────────
  { id: 'dc-gcse-revision-0211', deck_id: 'deck-gcse-revision', front: 'What are the mean, median, mode, and range?', back: 'Mean: sum of all values ÷ number of values.\nMedian: middle value when data is ordered (average of two middle values if even count).\nMode: most frequent value.\nRange: largest − smallest.\n\nExample: 3, 5, 5, 7, 10 → Mean = 6, Median = 5, Mode = 5, Range = 7.\n\nGCSE Tip: Mean is affected by outliers. Median is more representative for skewed data. Mode is the only average for categorical data.', sort_order: 211 },
  { id: 'dc-gcse-revision-0212', deck_id: 'deck-gcse-revision', front: 'How do you calculate the mean from a frequency table?', back: 'Mean = (Σ fx) / (Σ f)\n  where f = frequency and x = data value.\n\nAdd a "fx" column (multiply each value by its frequency), sum it, then divide by total frequency.\n\nExample:\nValue(x): 1, 2, 3, 4  |  Freq(f): 3, 5, 2, 2  |  fx: 3, 10, 6, 8\nΣf = 12; Σfx = 27; Mean = 27/12 = 2.25\n\nGCSE Tip: NEVER just average the x-values without using frequencies.', sort_order: 212 },
  { id: 'dc-gcse-revision-0213', deck_id: 'deck-gcse-revision', front: 'How do you calculate the estimated mean from a grouped frequency table?', back: 'Use the midpoint of each class interval as x.\n\nMean ≈ Σ(midpoint × frequency) / Σ(frequency)\n\nExample:\nClass: 0-10, 10-20, 20-30 | Midpoint: 5, 15, 25 | Freq: 4, 7, 3\nΣfx = 20+105+75 = 200; Σf = 14; Mean ≈ 200/14 ≈ 14.3\n\nGCSE Tip: This is an ESTIMATE because we assume all values are at the midpoint. State "estimated mean" in your answer.', sort_order: 213 },
  { id: 'dc-gcse-revision-0214', deck_id: 'deck-gcse-revision', front: 'How do you find the median from a frequency table?', back: 'Cumulative frequencies: add frequencies in order.\nMedian position = (n+1)/2 th value (for raw data) or n/2 th value (for large datasets).\n\nExample: 12 data points → median position = 6.5th → average of 6th and 7th.\nUsing cumulative freq: find which class the median position falls in.\n\nGCSE Tip: For grouped data, use the cumulative frequency curve (ogive) to read off the median at the 50% point.', sort_order: 214 },
  { id: 'dc-gcse-revision-0215', deck_id: 'deck-gcse-revision', front: 'How do you draw and interpret a cumulative frequency graph?', back: 'Steps:\n1. Add a cumulative frequency column (running total).\n2. Plot (upper class boundary, cumulative frequency).\n3. Join with a smooth S-curve.\n\nReading off:\n  Median: cumulative freq = n/2\n  LQ: cumulative freq = n/4\n  UQ: cumulative freq = 3n/4\n  IQR = UQ − LQ\n\nGCSE Tip: Plot at the UPPER boundary, not the midpoint. The curve should be S-shaped (never decrease).', sort_order: 215 },
  { id: 'dc-gcse-revision-0216', deck_id: 'deck-gcse-revision', front: 'What is the interquartile range (IQR) and why is it useful?', back: 'IQR = Upper Quartile − Lower Quartile = Q3 − Q1\n\nThe IQR measures the spread of the middle 50% of the data — it is not affected by outliers.\n\nGCSE Tip: Compare distributions using median (location) and IQR (spread). Say e.g. "Group A has a higher median (75 vs 65) and a smaller IQR (15 vs 25), so Group A has higher AND more consistent results."', sort_order: 216 },
  { id: 'dc-gcse-revision-0217', deck_id: 'deck-gcse-revision', front: 'How do you draw and interpret a box plot (box and whisker diagram)?', back: 'Box plot shows: minimum, lower quartile (LQ), median, upper quartile (UQ), maximum.\n\nBox: from LQ to UQ (width = IQR).\nMedian line inside the box.\nWhiskers: from min to LQ and UQ to max.\n\nTo compare two box plots: compare medians (average value) and IQRs (spread/consistency).\n\nGCSE Tip: Box plots are always drawn to scale on a number line. A skewed box shows an asymmetric distribution.', sort_order: 217 },
  { id: 'dc-gcse-revision-0218', deck_id: 'deck-gcse-revision', front: 'How do you draw and interpret a histogram?', back: 'Histogram: for continuous grouped data.\n  Y-axis = frequency density (NOT frequency)\n  Frequency density = frequency / class width\n  Frequency = frequency density × class width = area of bar\n\nAll bars are adjacent (no gaps) — unlike a bar chart.\n\nGCSE Tip: Unequal class widths → you MUST use frequency density. Equal class widths → frequency density is proportional to frequency (you can use either).', sort_order: 218 },
  { id: 'dc-gcse-revision-0219', deck_id: 'deck-gcse-revision', front: 'How do you draw and interpret a frequency polygon?', back: 'Plot the frequency (or frequency density) at the midpoint of each class interval, then connect the points with straight lines.\n\nFor grouped data the midpoints are:\n  0–10 → 5; 10–20 → 15; 20–30 → 25; etc.\n\nGCSE Tip: Frequency polygons allow comparison of two datasets on the same axes — much clearer than overlapping histograms. Remember to use midpoints, not class boundaries.', sort_order: 219 },
  { id: 'dc-gcse-revision-0220', deck_id: 'deck-gcse-revision', front: 'What is scatter graph correlation and how do you describe it?', back: 'Positive correlation: as x increases, y increases. Points slope upward.\nNegative correlation: as x increases, y decreases. Points slope downward.\nNo correlation: no clear pattern.\n\nStrength: strong (points close to line of best fit), weak (points spread out).\n\nGCSE Tip: Correlation does NOT imply causation. Always state both the direction (positive/negative) and the strength (strong/weak).', sort_order: 220 },
  { id: 'dc-gcse-revision-0221', deck_id: 'deck-gcse-revision', front: 'How do you draw a line of best fit?', back: 'A line of best fit:\n  • Passes through (or close to) the mean point (x̄, ȳ).\n  • Has roughly equal numbers of points above and below.\n  • Extends across the full range of data.\n\nUse it for interpolation (within the data range) or extrapolation (outside — less reliable).\n\nGCSE Tip: Do NOT connect the first point to the last point. The line of best fit is a straight line — draw it with a ruler.', sort_order: 221 },
  { id: 'dc-gcse-revision-0222', deck_id: 'deck-gcse-revision', front: 'What is the difference between a bar chart, pie chart, and pictogram?', back: 'Bar chart: bars of equal width, height = frequency. Gaps between bars for discrete data.\nPie chart: sectors of a circle, angle = (frequency/total) × 360°.\nPictogram: symbols represent a fixed quantity; use half/quarter symbols for partial values.\n\nGCSE Tip: For a pie chart, calculate each angle: angle = (freq/total) × 360°. Check angles sum to 360°.', sort_order: 222 },
  { id: 'dc-gcse-revision-0223', deck_id: 'deck-gcse-revision', front: 'How do you draw a stem and leaf diagram?', back: 'Write the tens digit as the "stem" and the units as "leaves".\nOrder leaves numerically.\n\nExample: Data: 23, 17, 35, 28, 31, 19, 22, 35.\n  Stem | Leaf\n    1  | 7 9\n    2  | 2 3 8\n    3  | 1 5 5\n\nBack-to-back: two datasets sharing the same stem (leaves on both sides).\n\nGCSE Tip: Include a key (e.g. 2|3 means 23). Find median and quartiles directly from an ordered diagram.', sort_order: 223 },
  { id: 'dc-gcse-revision-0224', deck_id: 'deck-gcse-revision', front: 'How do you calculate and interpret the mean from a stem and leaf diagram?', back: 'Read all values from the diagram (stem × 10 + each leaf).\nSum all values, divide by number of values.\n\nFor median: find the middle position from the total count.\n  n values → median is at position (n+1)/2.\n\nGCSE Tip: Count the leaves to confirm n. An ordered stem-and-leaf diagram allows direct identification of minimum, maximum, LQ, median, UQ — all needed for a box plot.', sort_order: 224 },
  { id: 'dc-gcse-revision-0225', deck_id: 'deck-gcse-revision', front: 'What is sampling and what are different sampling methods?', back: 'Sampling: taking a subset of a population to draw conclusions about the whole.\n\nRandom sampling: every member has equal chance of selection.\nSystematic: every nth member selected from a list.\nStratified: population divided into groups; sample taken proportionally from each group.\n\nGCSE Tip: For stratified sampling: number from group = (group size/population) × sample size. This ensures representation of all subgroups.', sort_order: 225 },
  { id: 'dc-gcse-revision-0226', deck_id: 'deck-gcse-revision', front: 'How do you calculate a stratified sample?', back: 'Number sampled from a stratum = (stratum size / total population) × total sample size\n\nExample: School has 600 students: 250 Year 10, 350 Year 11. Sample 60 students.\n  Year 10: (250/600) × 60 = 25\n  Year 11: (350/600) × 60 = 35\n\nGCSE Tip: Check: 25 + 35 = 60 ✓. Each proportion represents the group correctly.', sort_order: 226 },
  { id: 'dc-gcse-revision-0227', deck_id: 'deck-gcse-revision', front: 'What is the difference between primary and secondary data?', back: 'Primary data: collected directly by the researcher (surveys, experiments, observations).\nSecondary data: already collected by someone else (internet, government records, newspaper statistics).\n\nAdvantages of primary: more relevant, tailored to the specific question.\nAdvantages of secondary: cheaper, faster, large datasets readily available.\n\nGCSE Tip: A GCSE question may ask you to identify or evaluate which type is used and why it might be biased.', sort_order: 227 },
  { id: 'dc-gcse-revision-0228', deck_id: 'deck-gcse-revision', front: 'How do you identify and avoid bias in data collection?', back: 'Bias occurs when the method of collection favours certain outcomes.\n\nSources of bias:\n  • Biased sample (not representative)\n  • Leading questions ("Don\'t you agree that…?")\n  • Poorly defined response options\n  • Too small a sample\n\nGCSE Tip: A questionnaire criticism question: look for leading questions, no "no opinion" option, ambiguous wording, overlapping intervals in response boxes.', sort_order: 228 },
  { id: 'dc-gcse-revision-0229', deck_id: 'deck-gcse-revision', front: 'How do you draw and interpret a two-way table?', back: 'A two-way table organises data by two categories.\n\nTo complete: use totals (row total + column total = grand total) to find missing values.\n\nExample:\n         Cat  Dog  Total\nMale:     8    12    20\nFemale:   6     9    15\nTotal:   14    21    35\n\nP(female AND cat) = 6/35.\n\nGCSE Tip: Two-way tables often lead to probability questions. Identify row, column, and grand totals first.', sort_order: 229 },
  { id: 'dc-gcse-revision-0230', deck_id: 'deck-gcse-revision', front: 'How do you compare two data sets using statistics?', back: 'Compare location (average): use mean or median.\nCompare spread: use range or IQR.\n\nExample: "Class A has a median of 72 and an IQR of 12. Class B has a median of 65 and IQR of 20. Class A performs better on average and is more consistent."\n\nGCSE Tip: Always make a comparison — don\'t just state the statistics. Use phrases like "Class A has a higher/lower median than Class B." Two comparisons expected for full marks.', sort_order: 230 },
  { id: 'dc-gcse-revision-0231', deck_id: 'deck-gcse-revision', front: 'What is an outlier and how do you identify one?', back: 'An outlier is a data value that is significantly different from the others.\n\nFormal rule: outlier if value < Q1 − 1.5 × IQR  or  > Q3 + 1.5 × IQR\n\nGCSE: often just "a value much larger/smaller than the rest" — recognise from the box plot (whisker extends unusually far).\n\nGCSE Tip: Outliers can distort the mean — the median is more appropriate when outliers are present.', sort_order: 231 },
  { id: 'dc-gcse-revision-0232', deck_id: 'deck-gcse-revision', front: 'What is frequency density and how is it used in histograms?', back: 'Frequency density = frequency / class width\nFrequency = frequency density × class width (= area of bar)\n\nGCSE Tip: If all class widths are equal, the bar heights ARE proportional to frequency. But with unequal class widths, ALWAYS calculate frequency density. A common mistake is reading frequencies directly from bar heights in a histogram.', sort_order: 232 },
  { id: 'dc-gcse-revision-0233', deck_id: 'deck-gcse-revision', front: 'How do you estimate the number of data points in a histogram interval?', back: 'Frequency = frequency density × class width = area of bar\n\nTo estimate proportion of values above/below a value within a class: assume uniform distribution within the bar.\n\nExample: Class 20–30 has frequency density 3.5 and class width 10 → frequency = 35.\nEstimate above 25 in this class: half of 35 = 17.5 ≈ 18 values.\n\nGCSE Tip: Use area = frequency for any region of a histogram.', sort_order: 233 },
  { id: 'dc-gcse-revision-0234', deck_id: 'deck-gcse-revision', front: 'How do you interpret time series graphs?', back: 'Time series: data plotted over time on a line graph. Shows trends, seasonal variation, and cycles.\n\nMoving average: smooths out fluctuations to show the underlying trend.\n  4-point moving average = mean of 4 consecutive values (centred for seasonal data).\n\nGCSE Tip: Identify the trend (upward, downward, or stable) and any seasonal patterns. "Describe the trend" requires you to identify the general direction, not every fluctuation.', sort_order: 234 },
  { id: 'dc-gcse-revision-0235', deck_id: 'deck-gcse-revision', front: 'How do you calculate a moving average?', back: '4-point moving average (example): data for quarters Q1–Q8.\n  MA₁ = (Q1+Q2+Q3+Q4)/4\n  MA₂ = (Q2+Q3+Q4+Q5)/4\n  etc.\n\nPlot each moving average at the midpoint of its group of values.\n\nGCSE Tip: A 4-point moving average is commonly used for quarterly data to remove seasonal variation. Plots centred between 2nd and 3rd values of each group.', sort_order: 235 },
  { id: 'dc-gcse-revision-0236', deck_id: 'deck-gcse-revision', front: 'What is the difference between discrete and continuous data?', back: 'Discrete data: can only take specific values (usually whole numbers). E.g. number of cars, shoe size.\n  → Bar chart, pictogram, stem-and-leaf, frequency polygon.\n\nContinuous data: can take any value in a range. E.g. height, weight, time.\n  → Histogram (frequency density), cumulative frequency.\n\nGCSE Tip: Histograms are always for continuous data. Bar charts always for discrete/categorical data. Gaps between bars = discrete; no gaps = continuous.', sort_order: 236 },
  { id: 'dc-gcse-revision-0237', deck_id: 'deck-gcse-revision', front: 'How do you find the class with the highest frequency density vs highest frequency?', back: 'These are DIFFERENT things if class widths vary:\n\nHighest frequency density: the tallest bar on a histogram.\nHighest frequency: the class with the largest AREA bar (freq = freq density × width).\n\nExample:\n  Class A: density 4, width 5 → freq = 20\n  Class B: density 3, width 10 → freq = 30\nClass B has more data but a shorter bar.\n\nGCSE Tip: Always calculate area (frequency) when class widths differ — never just compare bar heights.', sort_order: 237 },
  { id: 'dc-gcse-revision-0238', deck_id: 'deck-gcse-revision', front: 'What makes a good statistical hypothesis?', back: 'A hypothesis should be:\n  • Clear and specific (not vague)\n  • Testable using data\n  • Falsifiable (could be proven wrong)\n\nExample of a good hypothesis: "Students in Year 11 have a higher mean height than students in Year 10."\n\nGCSE Tip: In a statistical investigation, you collect data, calculate statistics, and compare them to the original hypothesis. Use statistical language: "This supports/does not support the hypothesis because…"', sort_order: 238 },
  { id: 'dc-gcse-revision-0239', deck_id: 'deck-gcse-revision', front: 'How do you interpret a pie chart?', back: 'Each sector angle represents a proportion of the total.\n  Proportion = angle / 360°\n  Frequency = (angle/360°) × total\n\nTo find an angle: angle = (frequency/total) × 360°.\n\nExample: 40 students, 15 prefer maths.\n  Angle = (15/40) × 360° = 135°\n\nGCSE Tip: If asked "how many students does the sector represent?", you must be given the total or be able to calculate it from another sector.', sort_order: 239 },
  { id: 'dc-gcse-revision-0240', deck_id: 'deck-gcse-revision', front: 'What is a questionnaire and how should one be designed?', back: 'A good questionnaire:\n  • Has a clear purpose\n  • Uses unbiased, non-leading questions\n  • Has response boxes that cover all possible answers (exhaustive)\n  • Has non-overlapping response boxes\n  • Is concise and clear\n\nBad example: "How often do you exercise? Rarely | Sometimes | Often" (vague, subjective)\nGood example: "How many times per week do you exercise? 0 | 1-2 | 3-4 | 5 or more"\n\nGCSE Tip: Questions asking you to "criticise" a questionnaire: look for leading questions, overlapping classes, missing option, or ambiguous wording.', sort_order: 240 },
  { id: 'dc-gcse-revision-0241', deck_id: 'deck-gcse-revision', front: 'How do you draw a cumulative frequency curve and estimate statistics from it?', back: 'Steps:\n1. Create a cumulative frequency table (upper boundary, cumulative total).\n2. Plot (upper boundary, cum. freq.) — start from (lower boundary of first class, 0).\n3. Join with a smooth S-shaped curve.\n\nEstimate:\n  Median: cum. freq. = n/2 → read x-value.\n  LQ: n/4; UQ: 3n/4\n  IQR = UQ − LQ\n\nGCSE Tip: Use a ruler to draw horizontal then vertical lines when reading values. The curve must be smooth.', sort_order: 241 },
  { id: 'dc-gcse-revision-0242', deck_id: 'deck-gcse-revision', front: 'What is meant by skewness in a data distribution?', back: 'Positive skew: tail extends to the right (most data on the left).\n  Mean > Median > Mode\n\nNegative skew: tail extends to the left (most data on the right).\n  Mean < Median < Mode\n\nSymmetric (no skew): Mean = Median = Mode. Normal distribution is symmetric.\n\nGCSE Tip: Look at the box plot — if the median is closer to the LQ, it is positively skewed. Closer to UQ = negatively skewed.', sort_order: 242 },
  { id: 'dc-gcse-revision-0243', deck_id: 'deck-gcse-revision', front: 'How do you read and interpret a back-to-back stem and leaf diagram?', back: 'Two data sets share the same stem (middle column). Leaves for one set go left, the other goes right.\n\nExample:\n  Boys | Stem | Girls\n  8 3  |  1   | 2 5 9\n  5 2  |  2   | 0 3 7\n\nBoys: 13, 18, 22, 25; Girls: 12, 15, 19, 20, 23, 27.\n\nGCSE Tip: Read boys\' leaves from right to left (they are reversed). Compare medians and ranges to describe differences.', sort_order: 243 },
  { id: 'dc-gcse-revision-0244', deck_id: 'deck-gcse-revision', front: 'What is interpolation and extrapolation in statistics?', back: 'Interpolation: using the line of best fit to estimate a value WITHIN the range of the data. More reliable.\n\nExtrapolation: using the line of best fit to predict a value OUTSIDE the range of the data. Less reliable — the relationship may not continue.\n\nGCSE Tip: Always state "this is an estimate" when reading from a graph. Extrapolation is "unreliable because the trend may not continue beyond the data range".', sort_order: 244 },
  { id: 'dc-gcse-revision-0245', deck_id: 'deck-gcse-revision', front: 'What are the key features to describe a distribution from a histogram or frequency diagram?', back: 'Describe:\n  1. Shape: symmetric, positive/negative skew, uniform, bimodal.\n  2. Centre: modal class (highest bar), estimated mean.\n  3. Spread: range, IQR.\n  4. Outliers: unusual values.\n\nGCSE Tip: "Describe the distribution" — always address shape and at least one measure of average and spread. One sentence each is enough.', sort_order: 245 },
  { id: 'dc-gcse-revision-0246', deck_id: 'deck-gcse-revision', front: 'How do you find and use the modal class?', back: 'The modal class is the class interval with the HIGHEST frequency (or highest frequency density for a histogram).\n\nExample:\nClass: 10–20, 20–30, 30–40\nFreq: 12, 20, 8\nModal class: 20–30 (highest frequency)\n\nNote: You cannot give a single mode for grouped data — only the modal class.\n\nGCSE Tip: Do not confuse "modal class" with "mode". The modal class is an interval, not a single value.', sort_order: 246 },
  { id: 'dc-gcse-revision-0247', deck_id: 'deck-gcse-revision', front: 'What is the difference between correlation and causation?', back: 'Correlation: a statistical relationship between two variables (they change together).\nCausation: one variable CAUSES the change in another.\n\nCorrelation does NOT imply causation.\n\nExample: Ice cream sales and drowning are positively correlated (both increase in summer) but one does not cause the other — a hidden variable (hot weather) drives both.\n\nGCSE Tip: Never say "x causes y" based solely on a scatter graph. Say "there is a positive/negative correlation between x and y".', sort_order: 247 },
  { id: 'dc-gcse-revision-0248', deck_id: 'deck-gcse-revision', front: 'How do you find the range and interquartile range from a list?', back: 'Sort the data in order first.\n\nRange = max − min\n\nLQ (Q1) = median of the lower half of data (below the overall median).\nUQ (Q3) = median of the upper half of data (above the overall median).\nIQR = Q3 − Q1\n\nExample: 3, 5, 7, 9, 11, 13, 15 (n=7)\n  Median = 9; LQ = median of {3,5,7} = 5; UQ = median of {11,13,15} = 13; IQR = 8\n\nGCSE Tip: For even n, split into two equal halves. For odd n, exclude the median.', sort_order: 248 },
  { id: 'dc-gcse-revision-0249', deck_id: 'deck-gcse-revision', front: 'How do you draw a box plot from a five-number summary?', back: 'Five-number summary: minimum, Q1, median, Q3, maximum.\n\nSteps:\n1. Draw a number line to scale.\n2. Mark and draw a box from Q1 to Q3.\n3. Mark the median inside the box.\n4. Draw whiskers from Q1 to minimum and Q3 to maximum.\n\nGCSE Tip: The box must be accurate to scale. Whiskers extend to the min/max values (not to outliers if they are marked separately with a cross).', sort_order: 249 },
  { id: 'dc-gcse-revision-0250', deck_id: 'deck-gcse-revision', front: 'What is a frequency table and how do you complete one?', back: 'A frequency table lists each value (or class) and its count (tally).\n\nFor continuous data: use class intervals.\nFor discrete data: individual values.\n\nCompletion: total all frequencies → should match n.\nAdd a "relative frequency" column = freq / total (gives proportion; sum = 1).\n\nGCSE Tip: Relative frequencies are useful for comparing datasets of different sizes and for calculating probabilities.', sort_order: 250 },

  // ── PROBABILITY (cards 251–270) ───────────────────────────────────────────
  { id: 'dc-gcse-revision-0251', deck_id: 'deck-gcse-revision', front: 'What is probability and how do you calculate basic probability?', back: 'Probability of event A = number of favourable outcomes / total number of equally likely outcomes\n  P(A) = n(A) / n(S)\n\nProbability is always between 0 (impossible) and 1 (certain).\nSum of all probabilities for all outcomes = 1.\n\nExample: P(rolling 4 on a fair die) = 1/6\n\nGCSE Tip: Express probabilities as fractions, decimals, or percentages. "Find the probability" → always a number between 0 and 1.', sort_order: 251 },
  { id: 'dc-gcse-revision-0252', deck_id: 'deck-gcse-revision', front: 'What is the complement of an event?', back: 'P(not A) = 1 − P(A)\n\nThe complement is everything that is NOT A.\n\nExample: P(rain) = 0.35 → P(no rain) = 1 − 0.35 = 0.65\n\nGCSE Tip: Use the complement when it is easier to calculate "not A" and subtract. "At least one" problems are often easier with the complement: P(at least one) = 1 − P(none).', sort_order: 252 },
  { id: 'dc-gcse-revision-0253', deck_id: 'deck-gcse-revision', front: 'What is the addition rule for probability (mutually exclusive events)?', back: 'Mutually exclusive events cannot both occur at the same time.\n\nP(A or B) = P(A) + P(B)\n\nExample: Rolling a die: P(2 or 5) = 1/6 + 1/6 = 2/6 = 1/3\n\nFor non-mutually exclusive events (A and B can both occur):\nP(A or B) = P(A) + P(B) − P(A and B)\n\nGCSE Tip: Check if events CAN happen simultaneously. If yes, subtract the overlap.', sort_order: 253 },
  { id: 'dc-gcse-revision-0254', deck_id: 'deck-gcse-revision', front: 'What is the multiplication rule for probability (independent events)?', back: 'Independent events: the outcome of one does not affect the other.\n\nP(A and B) = P(A) × P(B)\n\nExample: Tossing a coin twice: P(H then H) = ½ × ½ = ¼\n\nFor dependent events (sampling WITHOUT replacement):\nP(A then B) = P(A) × P(B | A)\n\nGCSE Tip: "Without replacement" → the probabilities change after the first pick. Draw a tree diagram.', sort_order: 254 },
  { id: 'dc-gcse-revision-0255', deck_id: 'deck-gcse-revision', front: 'How do you draw and use a probability tree diagram?', back: 'Tree diagrams show all possible outcomes in sequence.\n  • Branch probabilities (from each node) must sum to 1.\n  • Multiply along branches for AND (combined) probability.\n  • Add probabilities for OR (combined) outcomes.\n\nExample: P(red then blue) = P(red) × P(blue|red)\n\nGCSE Tip: Always label branches AND outcomes at the end. Calculate P for each branch combination, then add as needed.', sort_order: 255 },
  { id: 'dc-gcse-revision-0256', deck_id: 'deck-gcse-revision', front: 'How do you calculate probabilities for sampling without replacement?', back: 'After removing an item, the total decreases by 1 (denominator changes).\n\nExample: Bag has 5 red, 3 blue. Pick two without replacement.\n  P(both red) = (5/8) × (4/7) = 20/56 = 5/14\n  P(one of each) = P(RB) + P(BR) = (5/8)(3/7) + (3/8)(5/7) = 15/56 + 15/56 = 30/56 = 15/28\n\nGCSE Tip: Use a tree diagram to avoid errors. The second fraction changes based on what was picked first.', sort_order: 256 },
  { id: 'dc-gcse-revision-0257', deck_id: 'deck-gcse-revision', front: 'How do you use a Venn diagram for probability?', back: 'Draw two overlapping circles (A and B) inside a rectangle (sample space).\n\nRegions:\n  A only: P(A) − P(A∩B)\n  B only: P(B) − P(A∩B)\n  A∩B (overlap): P(both A and B)\n  Outside both: P(neither) = 1 − P(A∪B)\n  A∪B: P(A or B) = P(A) + P(B) − P(A∩B)\n\nGCSE Tip: Fill in the overlap first, then calculate the remaining regions. Numbers in the circles should sum to the total.', sort_order: 257 },
  { id: 'dc-gcse-revision-0258', deck_id: 'deck-gcse-revision', front: 'What is conditional probability?', back: 'P(A|B) = probability of A given B has already occurred.\n  P(A|B) = P(A∩B) / P(B)\n\nExample: From a class of 30: 12 play football, 8 play tennis, 5 play both.\n  P(tennis | football) = P(both) / P(football) = (5/30) / (12/30) = 5/12\n\nFrom a two-way table: restrict attention to the relevant row/column.\n\nGCSE Tip: "Given that…" signals conditional probability. Restrict the sample space to the given condition.', sort_order: 258 },
  { id: 'dc-gcse-revision-0259', deck_id: 'deck-gcse-revision', front: 'What is the expected frequency?', back: 'Expected frequency = probability × number of trials\n\nExample: P(rolling a 6) = 1/6. Roll a die 120 times.\n  Expected frequency of 6 = 120 × (1/6) = 20\n\nCompare with observed frequency to assess whether a die is fair.\n\nGCSE Tip: Expected frequency can be a decimal — that is fine (it is an average over many experiments). Do NOT round when comparing with observed.', sort_order: 259 },
  { id: 'dc-gcse-revision-0260', deck_id: 'deck-gcse-revision', front: 'What is relative frequency and how does it relate to probability?', back: 'Relative frequency = number of times event occurred / total number of trials\n\nAs the number of trials increases, relative frequency approaches the theoretical probability (Law of Large Numbers).\n\nGCSE Tip: Used for experimental probability. Plot relative frequency vs number of trials — the graph should stabilise (converge) towards the theoretical probability. A large number of trials gives a more reliable estimate.', sort_order: 260 },
  { id: 'dc-gcse-revision-0261', deck_id: 'deck-gcse-revision', front: 'How do you use a sample space diagram for probability?', back: 'List all possible outcomes in a grid.\n\nExample: Two dice — rows = die 1 (1–6), columns = die 2 (1–6).\n  Total outcomes = 36.\n  P(sum = 7) = 6/36 = 1/6 (count outcomes where row+col=7: (1,6),(2,5),(3,4),(4,3),(5,2),(6,1)).\n\nGCSE Tip: A sample space diagram makes it easy to count outcomes. Always verify total = n(S) before reading off probabilities.', sort_order: 261 },
  { id: 'dc-gcse-revision-0262', deck_id: 'deck-gcse-revision', front: 'How do you find P(at least one) using the complement?', back: 'P(at least one) = 1 − P(none)\n\nExample: Probability of a machine failing on any given day = 0.1.\n  P(fails at least once in 3 days) = 1 − P(no failures)\n  = 1 − (0.9)³ = 1 − 0.729 = 0.271\n\nGCSE Tip: "At least one" is the complement of "none". This is nearly always easier than listing all cases with at least one occurrence.', sort_order: 262 },
  { id: 'dc-gcse-revision-0263', deck_id: 'deck-gcse-revision', front: 'What is a frequency tree and how is it used?', back: 'A frequency tree shows actual counts (not probabilities) at each branch.\n\nExample: 200 students; 120 study maths. Of those, 80 also study science. Of non-maths (80), 30 study science.\n\nRead directly: P(maths AND science) = 80/200 = 2/5.\nP(science) = (80+30)/200 = 110/200 = 11/20.\n\nGCSE Tip: Fill all branches so each node\'s counts sum correctly. Frequency trees are especially useful for conditional probability.', sort_order: 263 },
  { id: 'dc-gcse-revision-0264', deck_id: 'deck-gcse-revision', front: 'How do you identify mutually exclusive vs independent events?', back: 'Mutually exclusive: P(A and B) = 0 (cannot happen simultaneously).\n  Example: rolling a 3 and a 5 on one die.\n\nIndependent: P(A and B) = P(A) × P(B) (one does not affect the other).\n  Example: flipping a coin twice.\n\nMutually exclusive events are NOT independent (unless one has probability 0).\n\nGCSE Tip: "Can both happen at the same time?" → if no, they are mutually exclusive. "Does knowing A happened change P(B)?" → if no, they are independent.', sort_order: 264 },
  { id: 'dc-gcse-revision-0265', deck_id: 'deck-gcse-revision', front: 'How do you use a two-way table to find conditional probabilities?', back: 'Restrict to the given condition (relevant row or column), then count within it.\n\nExample (from the table):\n         Passed  Failed  Total\nMale:      18      6      24\nFemale:    14     12      26\nTotal:     32     18      50\n\nP(passed | male) = 18/24 = 3/4\nP(female | failed) = 12/18 = 2/3\n\nGCSE Tip: The denominator for a conditional probability is the TOTAL in the given row/column, not the overall total.', sort_order: 265 },
  { id: 'dc-gcse-revision-0266', deck_id: 'deck-gcse-revision', front: 'What are the three regions of a Venn diagram for two sets?', back: 'For events A and B:\n  A only (A ∩ B\'): in A but not B\n  B only (A\' ∩ B): in B but not A\n  A ∩ B (intersection): in both A and B\n  A\' ∩ B\' (outside both): in neither A nor B\n\nThese four regions are mutually exclusive and exhaustive.\n\nGCSE Tip: Label all four regions and check they sum to the total. The union A∪B = A only + B only + A∩B.', sort_order: 266 },
  { id: 'dc-gcse-revision-0267', deck_id: 'deck-gcse-revision', front: 'How do you use the formula P(A∪B) = P(A) + P(B) − P(A∩B)?', back: 'This avoids double-counting the overlap.\n\nExample: P(A) = 0.4, P(B) = 0.3, P(A∩B) = 0.1\n  P(A or B) = 0.4 + 0.3 − 0.1 = 0.6\n  P(neither A nor B) = 1 − 0.6 = 0.4\n\nGCSE Tip: If events are mutually exclusive, P(A∩B) = 0, so P(A∪B) = P(A)+P(B). The formula becomes the simpler addition rule.', sort_order: 267 },
  { id: 'dc-gcse-revision-0268', deck_id: 'deck-gcse-revision', front: 'What is the difference between theoretical and experimental probability?', back: 'Theoretical: calculated from equally likely outcomes using logic.\n  P(head) = 1/2 for a fair coin.\n\nExperimental (relative frequency): based on actual results.\n  Toss coin 100 times, get 47 heads → experimental P(head) = 0.47.\n\nAs trials → ∞, experimental → theoretical (Law of Large Numbers).\n\nGCSE Tip: A biased coin would have experimental probability consistently ≠ 0.5. More trials = more reliable estimate.', sort_order: 268 },
  { id: 'dc-gcse-revision-0269', deck_id: 'deck-gcse-revision', front: 'How do you find probability from a Venn diagram with three sets?', back: 'Label all 8 regions: A only, B only, C only, A∩B only, A∩C only, B∩C only, A∩B∩C, and outside all three.\n\nSteps:\n1. Fill in the centre (A∩B∩C) first.\n2. Work outward: fill A∩B, A∩C, B∩C (subtract the centre).\n3. Fill A only, B only, C only.\n4. Fill outside.\n\nGCSE Tip: Use a systematic inside-out approach. Check all regions sum to the total.', sort_order: 269 },
  { id: 'dc-gcse-revision-0270', deck_id: 'deck-gcse-revision', front: 'How do you use conditional probability in real-world contexts (e.g. medical tests)?', back: 'Example: Test for a condition. P(positive | has condition) = 0.95 (sensitivity). P(positive | no condition) = 0.05 (false positive).\n\nIf 1% of population has the condition:\n  In 1000 people: 10 have it, 990 don\'t.\n  True positives = 10 × 0.95 = 9.5\n  False positives = 990 × 0.05 = 49.5\n  P(has condition | positive) = 9.5/(9.5+49.5) ≈ 0.16 (only 16%!)\n\nGCSE Tip: Use a frequency tree with 1000 people to avoid confusion with conditional probabilities.', sort_order: 270 },

  // ── HIGHER ONLY TOPICS (cards 271–300) ────────────────────────────────────
  { id: 'dc-gcse-revision-0271', deck_id: 'deck-gcse-revision', front: 'What are the circle theorems for the angle at the centre?', back: 'The angle subtended at the centre by an arc is twice the angle subtended at the circumference by the same arc.\n\nIf ∠AOB = 2∠ACB (where O is the centre, C is any point on the major arc).\n\nGCSE Tip: Draw the radius to form the central angle. This theorem often appears alongside isosceles triangles (two radii = two equal sides). Always state "angle at centre = 2 × angle at circumference" as your reason.', sort_order: 271 },
  { id: 'dc-gcse-revision-0272', deck_id: 'deck-gcse-revision', front: 'What is function notation and how do you use it?', back: 'f(x) means "function of x" — a rule applied to the input x.\nf(3) means substitute x = 3 into the function.\n\nComposite function: fg(x) = f(g(x)) — apply g FIRST, then f.\nInverse function: f⁻¹(x) is the "undo" function; f(f⁻¹(x)) = x.\n\nGCSE Tip: fg ≠ gf. In "fg(x)", g is applied first. Always write out steps clearly.', sort_order: 272 },
  { id: 'dc-gcse-revision-0273', deck_id: 'deck-gcse-revision', front: 'How do you prove algebraic identities?', back: 'Work on ONE side only (usually the more complex side) and simplify/manipulate it until it equals the other side.\n\nExample: Prove (x+1)² − (x−1)² ≡ 4x\n  LHS = (x²+2x+1) − (x²−2x+1) = 4x ✓\n\nAlternatively: expand both sides independently and show they are equal.\n\nGCSE Tip: Never "move things across" the ≡ sign in a proof. Work each side separately.', sort_order: 273 },
  { id: 'dc-gcse-revision-0274', deck_id: 'deck-gcse-revision', front: 'What is the equation of a tangent to a curve at a given point?', back: 'For y = f(x) at point (a, f(a)):\n  Gradient of tangent = gradient of curve at x = a (read from a graph, or use calculus at A-level)\n\nFor a circle x²+y²=r² at (x₁,y₁):\n  Radius gradient = y₁/x₁\n  Tangent gradient = −x₁/y₁ (perpendicular)\n  Equation: y−y₁ = m(x−x₁)\n\nGCSE Tip: Tangent is perpendicular to the radius. Use point-slope form with the known point and calculated gradient.', sort_order: 274 },
  { id: 'dc-gcse-revision-0275', deck_id: 'deck-gcse-revision', front: 'How do you expand triple brackets?', back: 'Expand two brackets first, then expand the result by the third.\n\nExample: (x+1)(x+2)(x+3)\n  Step 1: (x+1)(x+2) = x²+3x+2\n  Step 2: (x²+3x+2)(x+3)\n    = x³+3x²+3x²+9x+2x+6\n    = x³+6x²+11x+6\n\nGCSE Tip: Take your time with Step 2 — expand each term systematically. There are six products to compute.', sort_order: 275 },
  { id: 'dc-gcse-revision-0276', deck_id: 'deck-gcse-revision', front: 'What are the key graph features of y = x³ and y = 1/x?', back: 'y = x³:\n  S-shaped cubic. Rotational symmetry about origin.\n  Passes through (−2,−8), (−1,−1), (0,0), (1,1), (2,8).\n\ny = 1/x (rectangular hyperbola):\n  Two branches in Q1 and Q3. Approaches but never touches axes (asymptotes at x=0 and y=0).\n  xy = 1 (constant product).\n\nGCSE Tip: Recognise these shapes from their equations. Transformations apply in the usual way.', sort_order: 276 },
  { id: 'dc-gcse-revision-0277', deck_id: 'deck-gcse-revision', front: 'How do you sketch a cubic graph y = ax³ + bx² + cx + d?', back: 'Key features:\n  1. Roots: solve y = 0 (up to 3 roots).\n  2. y-intercept: x = 0 → y = d.\n  3. Direction: a > 0 → goes down-left to up-right (like y = x³); a < 0 → reversed.\n  4. Repeated roots: graph touches but does not cross the x-axis.\n\nGCSE Tip: If factorised as (x−a)²(x−b): double root at a (touching), single root at b (crossing). Sketch accordingly.', sort_order: 277 },
  { id: 'dc-gcse-revision-0278', deck_id: 'deck-gcse-revision', front: 'How do you simplify expressions with surds including rationalising?', back: 'Simplify: find largest perfect square factor.\n  √180 = √(36×5) = 6√5\n\nAdd/subtract like surds:\n  3√2 + 5√2 = 8√2; 4√3 − √3 = 3√3\n\nRationalise 1/(a+√b): multiply by (a−√b)/(a−√b).\n  1/(3+√2) = (3−√2)/((3+√2)(3−√2)) = (3−√2)/(9−2) = (3−√2)/7\n\nGCSE Tip: The denominator (a²−b) uses difference of two squares — always a rational number.', sort_order: 278 },
  { id: 'dc-gcse-revision-0279', deck_id: 'deck-gcse-revision', front: 'How do you interpret the discriminant of a quadratic?', back: 'Discriminant: Δ = b² − 4ac\n\n  Δ > 0 → two distinct real roots (graph crosses x-axis twice)\n  Δ = 0 → one repeated root (graph touches x-axis once — tangent)\n  Δ < 0 → no real roots (graph does not cross x-axis)\n\nGCSE Tip: Used in "show that the equation has no real solutions" (show Δ < 0), or "find k such that the equation has equal roots" (set Δ = 0 and solve for k).', sort_order: 279 },
  { id: 'dc-gcse-revision-0280', deck_id: 'deck-gcse-revision', front: 'What is completing the square used for?', back: '1. Solving quadratics: rearrange to (x+p)² = q → x = −p ± √q\n2. Finding vertex of parabola: vertex is (−p, −q) from y = (x+p)² + q form.\n3. Identifying minimum/maximum: minimum value of y = q (for a>0).\n\nExample: y = x² − 4x + 7 = (x−2)² + 3\n  Vertex: (2, 3); minimum value of y = 3.\n\nGCSE Tip: For ax² + bx + c, factor out a first: a[(x + b/2a)² − (b/2a)² + c/a].', sort_order: 280 },
  { id: 'dc-gcse-revision-0281', deck_id: 'deck-gcse-revision', front: 'How do you use vectors to show that points are collinear?', back: 'Points A, B, C are collinear if AB = k × AC for some scalar k (i.e. one vector is a scalar multiple of another).\n\nExample: If AB = 3a + b and AC = 9a + 3b = 3(3a + b) = 3 × AB\n  → AB and AC are parallel and share point A → A, B, C are collinear.\n\nGCSE Tip: Always state: (1) the vectors are parallel (scalar multiples), and (2) they share a common point. Both points are needed for the collinearity proof.', sort_order: 281 },
  { id: 'dc-gcse-revision-0282', deck_id: 'deck-gcse-revision', front: 'How do you use the sine and cosine rules in multi-step problems?', back: 'Some problems require using the sine rule in one step and the cosine rule in the next.\n\nGeneral strategy:\n  • If given AAS/ASA/SSA → sine rule\n  • If given SAS/SSS → cosine rule\n  • For area → ½ab sin C\n\nAlways carry the full unrounded answer forward to avoid accumulating rounding error.\n\nGCSE Tip: Write down intermediate answers to 4 decimal places and only round at the final step.', sort_order: 282 },
  { id: 'dc-gcse-revision-0283', deck_id: 'deck-gcse-revision', front: 'What is the graph of y = aˣ and how do you interpret it?', back: 'For a > 1: exponential GROWTH — increases rapidly, passes through (0,1), always positive.\nFor 0 < a < 1: exponential DECAY — decreases toward 0, passes through (0,1).\n\nKey feature: y = 0 is a horizontal asymptote.\n\ny = 2ˣ vs y = 3ˣ: y = 3ˣ grows faster.\n\nGCSE Tip: All exponential graphs pass through (0,1) because a⁰ = 1. At x = 1, y = a (the base). Identify the base from the graph.', sort_order: 283 },
  { id: 'dc-gcse-revision-0284', deck_id: 'deck-gcse-revision', front: 'How do you solve equations involving index laws with fractional/negative indices?', back: '27^(−2/3) = 1 / 27^(2/3) = 1 / (∛27)² = 1/9\n\n16^(3/4) = (⁴√16)³ = 2³ = 8\n\n8^(−1/3) = 1/∛8 = 1/2\n\nGeneral: a^(m/n) = (ⁿ√a)ᵐ — take the ROOT first, then apply the POWER.\n\nGCSE Tip: Always root first (gives smaller numbers), then power. Negative index = reciprocal.', sort_order: 284 },
  { id: 'dc-gcse-revision-0285', deck_id: 'deck-gcse-revision', front: 'How do you solve equations of the form aˣ = b?', back: 'Use logarithms (or trial and improvement for GCSE):\n  aˣ = b → x = log b / log a\n\nExample: 2ˣ = 32 → 2ˣ = 2⁵ → x = 5 (match bases)\n  3ˣ = 20 → x = log 20 / log 3 ≈ 2.73\n\nGCSE Tip: If both sides can be expressed as the same base, equate indices. For others, use log on a calculator. This is a Higher-only skill.', sort_order: 285 },
  { id: 'dc-gcse-revision-0286', deck_id: 'deck-gcse-revision', front: 'What is iteration and how do you use it to find roots?', back: 'Rearrange the equation to the form x = g(x).\nUse: xₙ₊₁ = g(xₙ) with a starting value x₀.\n\nExample: x³ − 5x + 1 = 0 rearranged to x = (x³ + 1)/5\n  x₀ = 0: x₁ = 0.2; x₂ = (0.008+1)/5 = 0.2016; converges to ≈ 0.201\n\nGCSE Tip: Carry at least 4 decimal places between iterations. Show each substitution clearly. Stop when two consecutive values agree to the required accuracy.', sort_order: 286 },
  { id: 'dc-gcse-revision-0287', deck_id: 'deck-gcse-revision', front: 'What is the proof that the product of two odd numbers is odd?', back: 'Let the two odd numbers be (2m+1) and (2n+1), where m, n are integers.\n\n(2m+1)(2n+1) = 4mn + 2m + 2n + 1 = 2(2mn+m+n) + 1\n\nThis is of the form 2k+1 (where k = 2mn+m+n), which is ODD.\n\nGCSE Tip: Always define your letters ("let m and n be integers"), expand, then show the result has the required form. Conclude with a clear statement.', sort_order: 287 },
  { id: 'dc-gcse-revision-0288', deck_id: 'deck-gcse-revision', front: 'How do you prove that the sum of three consecutive integers is divisible by 3?', back: 'Let the three consecutive integers be n, n+1, n+2.\n\nSum = n + (n+1) + (n+2) = 3n + 3 = 3(n+1)\n\nThis is a multiple of 3, therefore divisible by 3. □\n\nGCSE Tip: "Let n be an integer" at the start. Factorise to show the required divisibility. The □ or QED symbol signals the end of the proof.', sort_order: 288 },
  { id: 'dc-gcse-revision-0289', deck_id: 'deck-gcse-revision', front: 'What is the proof that the difference of two squares is always even?', back: 'Let the two integers be n and m (with n > m).\n  n² − m² = (n+m)(n−m)\n\nCase 1: both even or both odd → (n+m) is even → product is even.\nCase 2: one even, one odd → (n−m) is odd, (n+m) is odd → product is odd.\n\nNote: this shows it is NOT always even (it depends on parities).\n\nGCSE Tip: "Difference of two squares" proofs need careful case analysis. Test with examples before generalising.', sort_order: 289 },
  { id: 'dc-gcse-revision-0290', deck_id: 'deck-gcse-revision', front: 'How do you sketch a reciprocal function y = k/x (hyperbola)?', back: 'y = k/x has asymptotes at x = 0 (y-axis) and y = 0 (x-axis).\n\nFor k > 0: two branches in Q1 (x>0,y>0) and Q3 (x<0,y<0).\nFor k < 0: two branches in Q2 and Q4.\n\nThe graph is a rectangular hyperbola — as x → ∞, y → 0.\n\nGCSE Tip: Plot a few key points (1,k), (2,k/2), (−1,−k) etc. Never let the curve touch the axes.', sort_order: 290 },
  { id: 'dc-gcse-revision-0291', deck_id: 'deck-gcse-revision', front: 'How do you find the nth term of a geometric sequence?', back: 'nth term: Tₙ = a × rⁿ⁻¹\n  a = first term, r = common ratio.\n\nExample: 2, 6, 18, 54, … → a=2, r=3 → Tₙ = 2 × 3ⁿ⁻¹\n  T₅ = 2 × 3⁴ = 162\n\nTo find r: r = T₂/T₁ (ratio of consecutive terms).\n\nGCSE Tip: Always verify by substituting n=1 (gives T₁ = a × r⁰ = a ✓). A geometric sequence grows exponentially.', sort_order: 291 },
  { id: 'dc-gcse-revision-0292', deck_id: 'deck-gcse-revision', front: 'How do you factorise by grouping?', back: 'Group terms in pairs, factor each pair, then factor out the common bracket.\n\nExample: x³ + 2x² + 3x + 6\n  = x²(x + 2) + 3(x + 2)\n  = (x² + 3)(x + 2)\n\nGCSE Tip: Works when the first pair and second pair give the same bracket. If not, try regrouping. Used for cubic factorisation alongside the factor theorem.', sort_order: 292 },
  { id: 'dc-gcse-revision-0293', deck_id: 'deck-gcse-revision', front: 'What are simultaneous equations with a quadratic?', back: 'Solve using substitution: express one variable from the linear equation and substitute into the quadratic.\n\nExample: y = x + 2 and y = x²\n  x² = x + 2 → x² − x − 2 = 0 → (x−2)(x+1) = 0\n  x = 2 (y=4) or x = −1 (y=1)\n\nGCSE Tip: Always give both pairs of solutions. Substitute both values of x into the LINEAR equation to find y — it is simpler.', sort_order: 293 },
  { id: 'dc-gcse-revision-0294', deck_id: 'deck-gcse-revision', front: 'How do you use graph transformations on y = sin(x) and y = cos(x)?', back: 'y = sin(x) + c: shifts up c units\ny = sin(x + d): shifts LEFT by d units\ny = a sin(x): amplitude changes to |a|\ny = sin(bx): period = 360°/b\ny = −sin(x): reflection in x-axis\n\nExample: y = 2 sin(3x) has amplitude 2, period 120°.\ny = cos(x − 30°) shifts the cosine graph 30° to the RIGHT.\n\nGCSE Tip: "Inside" the function → horizontal effect (counterintuitive direction). "Outside" → vertical effect.', sort_order: 294 },
  { id: 'dc-gcse-revision-0295', deck_id: 'deck-gcse-revision', front: 'What is the difference of two cubes formula?', back: 'a³ − b³ = (a − b)(a² + ab + b²)\na³ + b³ = (a + b)(a² − ab + b²)\n\nExamples:\n  x³ − 8 = (x−2)(x²+2x+4)\n  27 + y³ = (3+y)(9−3y+y²)\n\nGCSE Tip: These formulas appear less frequently at GCSE but are expected at Higher level. Verify by expanding.', sort_order: 295 },
  { id: 'dc-gcse-revision-0296', deck_id: 'deck-gcse-revision', front: 'How do you prove that a given formula always gives an integer, even number, etc.?', back: 'General approach:\n1. Expand and simplify the expression.\n2. Recognise the form (e.g. 2k → even; 2k+1 → odd; 3k → divisible by 3).\n\nExample: Prove n(n+1) is always even.\n  Either n or n+1 is even (consecutive integers).\n  Their product includes an even factor → always even.\n\nGCSE Tip: Look for opportunities to factorise the expression into a form that clearly shows the required property.', sort_order: 296 },
  { id: 'dc-gcse-revision-0297', deck_id: 'deck-gcse-revision', front: 'How do you find and interpret the gradient function (rate of change) from a graph?', back: 'Draw a tangent at the point of interest (a straight line touching the curve).\nMeasure the gradient of the tangent: rise / run.\n\nThis gradient = instantaneous rate of change at that point.\n\nGCSE Tip: For a velocity-time graph: gradient = acceleration. For a distance-time graph: gradient = speed. For a financial graph: gradient = rate of increase/decrease (e.g. cost per year). Always attach units.', sort_order: 297 },
  { id: 'dc-gcse-revision-0298', deck_id: 'deck-gcse-revision', front: 'How do you solve a system with a linear and a circle equation?', back: 'Substitute the linear into the circle equation.\n\nExample: y = 2x − 1 and x² + y² = 10\n  x² + (2x−1)² = 10\n  x² + 4x² − 4x + 1 = 10\n  5x² − 4x − 9 = 0\n  (5x−9)(x+1) = 0 → x = 9/5 or −1\n  y = 13/5 or −3\n\nGCSE Tip: Always substitute into the LINEAR equation to find y (avoids the ± complication of the circle).', sort_order: 298 },
  { id: 'dc-gcse-revision-0299', deck_id: 'deck-gcse-revision', front: 'What is the area under a velocity-time graph?', back: 'Area under a velocity-time graph = distance travelled.\n\nFor triangles: ½bh; trapeziums: ½(a+b)h; rectangles: bh.\n\nIf the graph dips below the x-axis: that portion represents motion in the opposite direction — calculate area as positive for distance, or treat as negative for displacement.\n\nGCSE Tip: Divide the graph into simple shapes. Use exact values from the graph for base and height.', sort_order: 299 },
  { id: 'dc-gcse-revision-0300', deck_id: 'deck-gcse-revision', front: 'How do you revise effectively for GCSE Maths?', back: 'Key strategies:\n  1. Active recall: use flashcards — test yourself rather than re-reading notes.\n  2. Spaced repetition: revisit topics at increasing intervals.\n  3. Past papers: practise under timed conditions with mark schemes.\n  4. Target weak areas: identify topics that consistently lose marks.\n  5. Show working: method marks are awarded even if the final answer is wrong.\n  6. Formulas: know which are given and which must be memorised.\n\nGCSE Tip: Marks are not lost for wrong final answers if correct method is shown — always attempt every question!', sort_order: 300 },
];
